import { createServerSupabase } from '@/lib/supabase-server'
import { redirect } from 'next/navigation'
import FichaClient from './FichaClient'

export default async function FichaPage({ searchParams }: { searchParams: { id?: string, mestre?: string } }) {
  const supabase = await createServerSupabase()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/auth/login')

  const { data: perfil } = await supabase.from('perfis').select('role, nome').eq('id', user.id).single()
  const isMestre = ['mestre','admin'].includes(perfil?.role ?? '')

  let ficha = null
  let fichaId = searchParams.id

  if (fichaId) {
    const { data } = await supabase.from('fichas').select('*').eq('id', fichaId).single()
    ficha = data
  } else {
    // Jogador: pega a própria ficha (a mais recente)
    const { data } = await supabase.from('fichas').select('*')
      .eq('jogador_id', user.id).order('criada_em', { ascending: false }).limit(1).single()
    ficha = data
    fichaId = ficha?.id
  }

  if (!ficha && !searchParams.id) redirect('/perfil')

  return (
    <FichaClient
      fichaInicial={ficha}
      fichaId={fichaId ?? null}
      isMestre={isMestre && !!searchParams.mestre}
      userId={user.id}
      userName={perfil?.nome ?? user.email ?? ''}
    />
  )
}
